import network
import time
import machine
import umqtt.simple as mqtt
import json
import dht

# WiFi credentials
SSID = 'your_ssid'
PASSWORD = 'your_password'

# MQTT broker details
BROKER_IP = 'your_broker_ip'
CLIENT_ID = 'esp32_sensor'

# Initialize DHT sensor
sensor = dht.DHT11(machine.Pin(4))

# Connect to WiFi
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(SSID, PASSWORD)
    while not wlan.isconnected():
        time.sleep(1)
    print('Connected to WiFi:', wlan.ifconfig())

# Publish temperature data
def publish_temperature(client):
    sensor.measure()
    temperature = sensor.temperature()
    payload = json.dumps({'temperature': temperature})
    client.publish("sensors/temp", payload)
    print('Published:', payload)

# Main function
def main():
    connect_wifi()
    client = mqtt.MQTTClient(CLIENT_ID, BROKER_IP, ssl=True)
    client.connect()
    
    while True:
        publish_temperature(client)
        time.sleep(10)

# Run the main function
main()